package main
import "fmt"

func readDatabase() {
    fmt.Println("1. Opening Database Connection...")

    // We "schedule" the closing right away!
    defer fmt.Println("3. Closing Database Connection...")

    fmt.Println("2. Reading Data...")
    // If we returned early here, the defer would STILL run!
}

func main() {
    readDatabase()
}
